using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;

namespace ContosoUniversity.Tests.Helpers
{
    public static class TestDbContextHelper
    {
        public static SchoolContext CreateContext(string databaseName = null)
        {
            databaseName ??= Guid.NewGuid().ToString();
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName)
                .Options;
            return new SchoolContext(options);
        }

        public static SchoolContext CreateSeededContext(string databaseName = null)
        {
            var context = CreateContext(databaseName);
            SeedData(context);
            return context;
        }

        public static void SeedData(SchoolContext context)
        {
            var instructors = new[]
            {
                new Instructor { ID = 1, FirstMidName = "Kim", LastName = "Abercrombie", HireDate = DateTime.Parse("1995-03-11"), CourseAssignments = new List<CourseAssignment>() },
                new Instructor { ID = 2, FirstMidName = "Fadi", LastName = "Fakhouri", HireDate = DateTime.Parse("2002-07-06"), CourseAssignments = new List<CourseAssignment>() },
                new Instructor { ID = 3, FirstMidName = "Roger", LastName = "Harui", HireDate = DateTime.Parse("1998-07-01"), CourseAssignments = new List<CourseAssignment>() },
            };
            context.Instructors.AddRange(instructors);
            context.SaveChanges();

            var departments = new[]
            {
                new Department { DepartmentID = 1, Name = "English", Budget = 350000, StartDate = DateTime.Parse("2007-09-01"), InstructorID = 1 },
                new Department { DepartmentID = 2, Name = "Mathematics", Budget = 100000, StartDate = DateTime.Parse("2007-09-01"), InstructorID = 2 },
            };
            context.Departments.AddRange(departments);
            context.SaveChanges();

            var courses = new[]
            {
