            mockFile.Setup(f => f.FileName).Returns(fileName);
            mockFile.Setup(f => f.Length).Returns(length);
            var ms = new MemoryStream(new byte[Math.Min(length, 1024)]);
            mockFile.Setup(f => f.CopyTo(It.IsAny<Stream>())).Callback<Stream>(s =>
            {
                ms.Position = 0;
                ms.CopyTo(s);
            });
            return mockFile;
        }
    }
