using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using Moq;
using System;
using System.IO;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class CoursesControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly CoursesController _controller;
        private readonly Mock<IWebHostEnvironment> _mockEnv;
        private readonly Mock<ILogger<CoursesController>> _mockLogger;
        private readonly string _tempDir;

        public CoursesControllerTests()
        {
            _context = TestDbContextHelper.CreateSeededContext();
            _mockEnv = new Mock<IWebHostEnvironment>();
            _mockLogger = new Mock<ILogger<CoursesController>>();
            _tempDir = Path.Combine(Path.GetTempPath(), Guid.NewGuid().ToString());
            Directory.CreateDirectory(_tempDir);
            _mockEnv.Setup(e => e.WebRootPath).Returns(_tempDir);
            _mockEnv.Setup(e => e.ContentRootPath).Returns(_tempDir);
            _controller = new CoursesController(_context, _mockEnv.Object, _mockLogger.Object);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
            if (Directory.Exists(_tempDir))
            {
                try { Directory.Delete(_tempDir, true); } catch { }
            }
        }

        [Fact]
        public void Index_ReturnsViewWithAllCourses()
        {
            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<Course>>(result.Model);
            Assert.Equal(3, model.Count);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithCourse()
        {
            var result = _controller.Details(1050) as ViewResult;

            Assert.NotNull(result);
            var course = Assert.IsType<Course>(result.Model);
            Assert.Equal("Chemistry", course.Title);
        }

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Create_Get_ReturnsViewWithDepartmentList()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        [Fact]
        public void Create_Post_ValidCourseNoImage_RedirectsToIndex()
        {
            var course = new Course
            {
                CourseID = 9999,
                Title = "New Course",
                Credits = 3,
                DepartmentID = 1
            };

            var result = _controller.Create(course, null) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Equal(4, _context.Courses.Count());
        }

        [Fact]
        public void Create_Post_ValidCourseWithImage_SavesFileAndRedirects()
        {
            var course = new Course
            {
                CourseID = 9998,
                Title = "Image Course",
                Credits = 3,
                DepartmentID = 1
            };
            var mockFile = CreateMockFormFile("test.jpg", 1024);

            var result = _controller.Create(course, mockFile.Object) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.NotNull(_context.Courses.Find(9998).TeachingMaterialImagePath);
        }

        [Fact]
        public void Create_Post_InvalidFileExtension_ReturnsViewWithError()
        {
            var course = new Course
            {
                CourseID = 9997,
                Title = "Bad Ext Course",
                Credits = 3,
                DepartmentID = 1
            };
            var mockFile = CreateMockFormFile("test.exe", 1024);

            var result = _controller.Create(course, mockFile.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Create_Post_FileTooLarge_ReturnsViewWithError()
        {
            var course = new Course
            {
                CourseID = 9996,
                Title = "Large File Course",
                Credits = 3,
                DepartmentID = 1
            };
            var mockFile = CreateMockFormFile("test.jpg", 6 * 1024 * 1024); // 6MB

            var result = _controller.Create(course, mockFile.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 9995, Title = "", Credits = 3, DepartmentID = 1 };

            var result = _controller.Create(course, null) as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithCourse()
        {
            var result = _controller.Edit(1050) as ViewResult;

            Assert.NotNull(result);
            var course = Assert.IsType<Course>(result.Model);
            Assert.Equal("Chemistry", course.Title);
        }

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Edit_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(9999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_Post_ValidCourseNoImage_RedirectsToIndex()
        {
            var course = _context.Courses.First();
            course.Title = "Updated Chemistry";
            _context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var result = _controller.Edit(course, null) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Edit_Post_InvalidFileExtension_ReturnsView()
        {
            var course = _context.Courses.First();
            _context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;
            var mockFile = CreateMockFormFile("test.exe", 1024);

            var result = _controller.Edit(course, mockFile.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsViewWithCourse()
        {
            var result = _controller.Delete(1050) as ViewResult;

            Assert.NotNull(result);
            var course = Assert.IsType<Course>(result.Model);
            Assert.Equal("Chemistry", course.Title);
        }

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void DeleteConfirmed_ValidId_RemovesCourseAndRedirects()
        {
            var result = _controller.DeleteConfirmed(1050) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Equal(2, _context.Courses.Count());
        }

        private Mock<IFormFile> CreateMockFormFile(string fileName, long length)
        {
            var mockFile = new Mock<IFormFile>();
            mockFile.Setup(f => f.FileName).Returns(fileName);
            mockFile.Setup(f => f.Length).Returns(length);
            var ms = new MemoryStream(new byte[Math.Min(length, 1024)]);
            mockFile.Setup(f => f.CopyTo(It.IsAny<Stream>())).Callback<Stream>(s =>
            {
                ms.Position = 0;
                ms.CopyTo(s);
            });
            return mockFile;
        }
    }
}

