using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class InstructorsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly InstructorsController _controller;

        public InstructorsControllerTests()
        {
            _context = TestDbContextHelper.CreateSeededContext();
            _controller = new InstructorsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void Index_NoParameters_ReturnsViewWithAllInstructors()
        {
            var result = _controller.Index(null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<ContosoUniversity.Models.SchoolViewModels.InstructorIndexData>(result.Model);
            Assert.Equal(3, model.Instructors.Count());
        }

        [Fact]
        public void Index_WithInstructorId_PopulatesCourses()
        {
            var result = _controller.Index(1, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<ContosoUniversity.Models.SchoolViewModels.InstructorIndexData>(result.Model);
            Assert.NotNull(model.Courses);
            Assert.NotEmpty(model.Courses);
        }

        [Fact]
        public void Index_WithCourseId_PopulatesEnrollments()
        {
            var result = _controller.Index(1, 1050) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<ContosoUniversity.Models.SchoolViewModels.InstructorIndexData>(result.Model);
            Assert.NotNull(model.Enrollments);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithInstructor()
        {
            var result = _controller.Details(1) as ViewResult;

            Assert.NotNull(result);
            var instructor = Assert.IsType<Instructor>(result.Model);
            Assert.Equal("Abercrombie", instructor.LastName);
        }

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Details_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Details(999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Create_Get_ReturnsViewWithInstructorAndCourses()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result.Model);
            Assert.NotNull(model.CourseAssignments);
            Assert.NotNull(_controller.ViewBag.Courses);
        }

        [Fact]
        public void Create_Post_ValidInstructor_RedirectsToIndex()
        {
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "Instructor",
                HireDate = DateTime.Parse("2020-01-01"),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _controller.Create(instructor, null) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Equal(4, _context.Instructors.Count());
        }

        [Fact]
        public void Create_Post_WithSelectedCourses_AssignsCourses()
        {
            var instructor = new Instructor
            {
                FirstMidName = "Course",
                LastName = "Instructor",
                HireDate = DateTime.Parse("2020-01-01"),
                CourseAssignments = new List<CourseAssignment>()
            };
            var selectedCourses = new[] { "1050", "4022" };

            var result = _controller.Create(instructor, selectedCourses) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var instructor = new Instructor
            {
                FirstMidName = "Test",
                LastName = "",
                HireDate = DateTime.Parse("2020-01-01"),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _controller.Create(instructor, null) as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithInstructor()
        {
            var result = _controller.Edit((int?)1) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result.Model);
            Assert.Equal("Abercrombie", model.LastName);
        }

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsViewWithInstructor()
        {
            var result = _controller.Delete(1) as ViewResult;

            Assert.NotNull(result);
            var instructor = Assert.IsType<Instructor>(result.Model);
            Assert.Equal("Abercrombie", instructor.LastName);
        }

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result.StatusCode);
        }

        [Fact]
        public void Delete_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void DeleteConfirmed_ValidId_RemovesInstructorAndRedirects()
        {
            // Remove course assignments first to allow deletion without FK issues
            var assignments = _context.CourseAssignments.Where(ca => ca.InstructorID == 3).ToList();
            _context.CourseAssignments.RemoveRange(assignments);
            _context.SaveChanges();

            // Add OfficeAssignment for the instructor being deleted
            _context.OfficeAssignments.Add(new OfficeAssignment { InstructorID = 3, Location = "Room 101" });
            _context.SaveChanges();

            var result = _controller.DeleteConfirmed(3) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Equal(2, _context.Instructors.Count());
        }

        [Fact]
        public void DeleteConfirmed_InstructorIsAdministrator_NullsDepartmentFK()
        {
            // Instructor 1 is administrator of Department 1
            // Remove course assignments first
            var assignments = _context.CourseAssignments.Where(ca => ca.InstructorID == 1).ToList();
            _context.CourseAssignments.RemoveRange(assignments);
            _context.SaveChanges();

            // Add required OfficeAssignment
            _context.OfficeAssignments.Add(new OfficeAssignment { InstructorID = 1, Location = "Room 102" });
            _context.SaveChanges();

            _controller.DeleteConfirmed(1);

            var dept = _context.Departments.Find(1);
            Assert.Null(dept.InstructorID);
        }
    }
}

