using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly StudentsController _controller;
        private readonly int _firstStudentId;

        public StudentsControllerTests()
        {
            _context = TestDbContextHelper.CreateSeededContext();
            _controller = new StudentsController(_context);
            // Set up TempData (needed for DeleteConfirmed error path)
            _controller.TempData = new TempDataDictionary(new DefaultHttpContext(), Mock.Of<ITempDataProvider>());
            _firstStudentId = _context.Students.OrderBy(s => s.LastName).First().ID;
        }

data.reasoningText:
Looking at the `DeleteConfirmed` method in StudentsController:

```csharp
public ActionResult DeleteConfirmed(int id)
{
    try
    {
        Student student = db.Students.Find(id);
        var studentName = $"{student.FirstMidName} {student.LastName}"; // NullRef if student is null
        db.Students.Remove(student);
        db.SaveChanges();
        ...
    }
    catch (Exception ex)
    {
        ...
        TempData["ErrorMessage"] = "Unable to delete the student...";
        return RedirectToAction("Index");
    }
}
```

The issue is that when `Find()` returns null for a non-existent student, accessing `student.FirstMidName` throws a NullReferenceException, which the catch block does catch. However, the catch block then tries to set `TempData`, which requires HttpContext to be properly configured—and without that setup, it would throw another exception. I need to configure TempData support or handle the null case before trying to access the student's properties.

Setting up HttpContext for the controller...

