using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.EntityFrameworkCore;
using System;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Data
{
    public class DbInitializerTests
    {
        [Fact]
        public void Initialize_EmptyDatabase_SeedsStudents()
        {
            using var context = TestDbContextHelper.CreateContext();
            DbInitializer.Initialize(context);

            Assert.Equal(8, context.Students.Count());
        }

        [Fact]
        public void Initialize_EmptyDatabase_SeedsInstructors()
        {
            using var context = TestDbContextHelper.CreateContext();
            DbInitializer.Initialize(context);

            Assert.Equal(5, context.Instructors.Count());
        }

        [Fact]
        public void Initialize_EmptyDatabase_SeedsDepartments()
        {
            using var context = TestDbContextHelper.CreateContext();
            DbInitializer.Initialize(context);

            Assert.Equal(4, context.Departments.Count());
        }

        [Fact]
        public void Initialize_EmptyDatabase_SeedsCourses()
        {
            using var context = TestDbContextHelper.CreateContext();
            DbInitializer.Initialize(context);

            Assert.Equal(7, context.Courses.Count());
        }

        [Fact]
        public void Initialize_EmptyDatabase_SeedsEnrollments()
        {
            using var context = TestDbContextHelper.CreateContext();
            DbInitializer.Initialize(context);

            Assert.Equal(11, context.Enrollments.Count());
        }

        [Fact]
        public void Initialize_EmptyDatabase_SeedsCourseAssignments()
        {
            using var context = TestDbContextHelper.CreateContext();
            DbInitializer.Initialize(context);

            Assert.Equal(8, context.CourseAssignments.Count());
        }

        [Fact]
        public void Initialize_EmptyDatabase_SeedsOfficeAssignments()
        {
            using var context = TestDbContextHelper.CreateContext();
            DbInitializer.Initialize(context);

            Assert.Equal(3, context.OfficeAssignments.Count());
        }

        [Fact]
        public void Initialize_AlreadySeeded_DoesNotDuplicate()
        {
            using var context = TestDbContextHelper.CreateContext();
            DbInitializer.Initialize(context);
            var studentCount = context.Students.Count();

            // Call again - should be idempotent
            DbInitializer.Initialize(context);

            Assert.Equal(studentCount, context.Students.Count());
        }

        [Fact]
        public void Initialize_SetsCorrectStudentData()
        {
            using var context = TestDbContextHelper.CreateContext();
            DbInitializer.Initialize(context);

            var carson = context.Students.First(s => s.LastName == "Alexander");
            Assert.Equal("Carson", carson.FirstMidName);
            Assert.Equal(DateTime.Parse("2010-09-01"), carson.EnrollmentDate);
        }

        [Fact]
        public void Initialize_SetsCorrectInstructorData()
        {
            using var context = TestDbContextHelper.CreateContext();
            DbInitializer.Initialize(context);

            var kim = context.Instructors.First(i => i.LastName == "Abercrombie");
            Assert.Equal("Kim", kim.FirstMidName);
            Assert.Equal(DateTime.Parse("1995-03-11"), kim.HireDate);
        }

        [Fact]
        public void Initialize_SetsDepartmentAdministrators()
        {
            using var context = TestDbContextHelper.CreateContext();
            DbInitializer.Initialize(context);

            var english = context.Departments.First(d => d.Name == "English");
            Assert.NotNull(english.InstructorID);
        }

        [Fact]
        public void Initialize_SetsCorrectCourseCredits()
        {
            using var context = TestDbContextHelper.CreateContext();
            DbInitializer.Initialize(context);

            var chemistry = context.Courses.First(c => c.Title == "Chemistry");
            Assert.Equal(3, chemistry.Credits);
            Assert.Equal(1050, chemistry.CourseID);
        }

        [Fact]
        public void Initialize_SetsCorrectEnrollmentGrades()
        {
            using var context = TestDbContextHelper.CreateContext();
            DbInitializer.Initialize(context);

            var enrollments = context.Enrollments.ToList();
            Assert.Contains(enrollments, e => e.Grade == Grade.A);
            Assert.Contains(enrollments, e => e.Grade == Grade.B);
            Assert.Contains(enrollments, e => e.Grade == Grade.C);
            Assert.Contains(enrollments, e => e.Grade == null);
        }

        [Fact]
        public void Initialize_SetsOfficeAssignmentLocations()
        {
            using var context = TestDbContextHelper.CreateContext();
            DbInitializer.Initialize(context);

            var offices = context.OfficeAssignments.ToList();
            Assert.Contains(offices, o => o.Location == "Smith 17");
            Assert.Contains(offices, o => o.Location == "Gowan 27");
            Assert.Contains(offices, o => o.Location == "Thompson 304");
        }
    }
}

using ContosoUniversity.Data;
using ContosoUniversity.Tests.Helpers;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Configuration;
using System.Collections.Generic;
using Xunit;

namespace ContosoUniversity.Tests.Data
{
    public class SchoolContextTests
    {
        [Fact]
        public void SchoolContext_ConfiguresCourseTable()
        {
            using var context = TestDbContextHelper.CreateContext();
            var entityType = context.Model.FindEntityType(typeof(ContosoUniversity.Models.Course));
            Assert.Equal("Course", entityType.GetTableName());
        }

        [Fact]
        public void SchoolContext_ConfiguresEnrollmentTable()
        {
            using var context = TestDbContextHelper.CreateContext();
            var entityType = context.Model.FindEntityType(typeof(ContosoUniversity.Models.Enrollment));
            Assert.Equal("Enrollment", entityType.GetTableName());
        }

        [Fact]
        public void SchoolContext_ConfiguresDepartmentTable()
        {
            using var context = TestDbContextHelper.CreateContext();
            var entityType = context.Model.FindEntityType(typeof(ContosoUniversity.Models.Department));
            Assert.Equal("Department", entityType.GetTableName());
        }

        [Fact]
        public void SchoolContext_ConfiguresCourseAssignmentCompositeKey()
        {
            using var context = TestDbContextHelper.CreateContext();
            var entityType = context.Model.FindEntityType(typeof(ContosoUniversity.Models.CourseAssignment));
            var primaryKey = entityType.FindPrimaryKey();
            Assert.Equal(2, primaryKey.Properties.Count);
        }

        [Fact]
        public void SchoolContext_ConfiguresPersonTPH()
        {
            using var context = TestDbContextHelper.CreateContext();
            var entityType = context.Model.FindEntityType(typeof(ContosoUniversity.Models.Person));
            Assert.Equal("Person", entityType.GetTableName());
        }

        [Fact]
        public void SchoolContext_HasAllDbSets()
        {
            using var context = TestDbContextHelper.CreateContext();
            Assert.NotNull(context.Courses);
            Assert.NotNull(context.Enrollments);
            Assert.NotNull(context.Departments);
            Assert.NotNull(context.Students);
            Assert.NotNull(context.Instructors);
            Assert.NotNull(context.OfficeAssignments);
            Assert.NotNull(context.CourseAssignments);
            Assert.NotNull(context.Notifications);
        }
    }

    public class SchoolContextFactoryTests
    {
        [Fact]
        public void Create_WithValidConfiguration_ReturnsContext()
        {
            var configuration = new ConfigurationBuilder()
                .AddInMemoryCollection(new Dictionary<string, string>
                {
                    ["ConnectionStrings:DefaultConnection"] = "Server=(localdb)\\mssqllocaldb;Database=Test;Trusted_Connection=True;"
                })
                .Build();

            var context = SchoolContextFactory.Create(configuration);

            Assert.NotNull(context);
            context.Dispose();
        }
    }
}

