using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using System;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class NotificationsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly NotificationsController _controller;

        public NotificationsControllerTests()
        {
            _context = TestDbContextHelper.CreateSeededContext();
            _controller = new NotificationsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void GetNotifications_ReturnsJsonResult()
        {
            var result = _controller.GetNotifications();

            Assert.NotNull(result);
            Assert.IsType<JsonResult>(result);
        }

        [Fact]
        public void GetNotifications_ReturnsSuccessTrue()
        {
            var result = _controller.GetNotifications();

            Assert.NotNull(result.Value);
            var value = result.Value;
            var successProp = value.GetType().GetProperty("success");
            Assert.NotNull(successProp);
            Assert.True((bool)successProp.GetValue(value));
        }

        [Fact]
        public void GetNotifications_ReturnsCountProperty()
        {
            var result = _controller.GetNotifications();

            var value = result.Value;
            var countProp = value.GetType().GetProperty("count");
            Assert.NotNull(countProp);
            var count = (int)countProp.GetValue(value);
            Assert.True(count >= 0);
        }

        [Fact]
        public void GetNotifications_AfterSendingNotification_ReturnsNotifications()
        {
            // Send a notification using the service exposed through BaseController
            var service = new NotificationService();
            service.SendNotification("Test", "1", "TestEntity", EntityOperation.CREATE, "Admin");

            var result = _controller.GetNotifications();

            var value = result.Value;
            var countProp = value.GetType().GetProperty("count");
            var count = (int)countProp.GetValue(value);
            // May or may not pick up this notification depending on queue state (shared static)
            Assert.True(count >= 0);
        }

        [Fact]
        public void MarkAsRead_ReturnsJsonWithSuccess()
        {
            var result = _controller.MarkAsRead(1);

            Assert.NotNull(result);
            var value = result.Value;
            var successProp = value.GetType().GetProperty("success");
            Assert.NotNull(successProp);
            Assert.True((bool)successProp.GetValue(value));
        }

        [Fact]
        public void MarkAsRead_AnyId_ReturnsSuccess()
        {
            // MarkAsRead is a no-op in the in-memory implementation
            var result = _controller.MarkAsRead(999);

            var value = result.Value;
            var successProp = value.GetType().GetProperty("success");
            Assert.True((bool)successProp.GetValue(value));
        }

        [Fact]
        public void Index_ReturnsView()
        {
            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
        }
    }
}

