[Fact]
public void Edit_Post_InvalidFileExtension_ReturnsView()
{
    var course = _context.Courses.First();
    _context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;
    var mockFile = CreateMockFormFile("test.exe", 1024);

    var result = _controller.Edit(course, mockFile.Object) as ViewResult;

    Assert.NotNull(result);
    Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
}

[Fact]
public void Edit_Post_ValidImage_UpdatesImagePath()
{
    var course = _context.Courses.First();
    _context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;
    var mockFile = CreateMockFormFile("newimage.png", 2048);

    var result = _controller.Edit(course, mockFile.Object) as RedirectToActionResult;

    Assert.NotNull(result);
    Assert.Equal("Index", result.ActionName);
}

[Fact]
public void Edit_Post_FileTooLarge_ReturnsViewWithError()
{
    var course = _context.Courses.First();
    _context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;
    var mockFile = CreateMockFormFile("big.jpg", 6 * 1024 * 1024);

    var result = _controller.Edit(course, mockFile.Object) as ViewResult;

    Assert.NotNull(result);
    Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
}

[Fact]
public void Edit_Post_InvalidModelState_ReturnsView()
{
    _controller.ModelState.AddModelError("Title", "Required");
    var course = new Course { CourseID = 1050, Title = "", Credits = 3, DepartmentID = 1 };

    var result = _controller.Edit(course, null) as ViewResult;

    Assert.NotNull(result);
}

[Fact]
public void DeleteConfirmed_CourseWithImage_DeletesFileAndRedirects()
{
    // Set up a course with a fake image path
    var course = _context.Courses.First();
    var imgDir = Path.Combine(_tempDir, "Uploads", "TeachingMaterials");
    Directory.CreateDirectory(imgDir);
    var imgPath = Path.Combine(imgDir, "test_image.jpg");
    File.WriteAllText(imgPath, "fake image");
    course.TeachingMaterialImagePath = "/Uploads/TeachingMaterials/test_image.jpg";
    _context.SaveChanges();

    var result = _controller.DeleteConfirmed(course.CourseID) as RedirectToActionResult;

    Assert.NotNull(result);
    Assert.Equal("Index", result.ActionName);
    Assert.False(File.Exists(imgPath));
}

