using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using System;
using System.Collections.Generic;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class PersonTests
    {
        [Fact]
        public void FullName_ReturnsLastNameCommaFirstName()
        {
            var student = new Student { FirstMidName = "Carson", LastName = "Alexander" };

            Assert.Equal("Alexander, Carson", student.FullName);
        }

        [Fact]
        public void FullName_Instructor_ReturnsCorrectFormat()
        {
            var instructor = new Instructor { FirstMidName = "Kim", LastName = "Abercrombie" };

            Assert.Equal("Abercrombie, Kim", instructor.FullName);
        }
    }

    public class StudentTests
    {
        [Fact]
        public void Student_InheritsFromPerson()
        {
            var student = new Student();
            Assert.IsAssignableFrom<Person>(student);
        }

        [Fact]
        public void Student_HasEnrollmentDateProperty()
        {
            var date = DateTime.Parse("2023-09-01");
            var student = new Student { EnrollmentDate = date };
            Assert.Equal(date, student.EnrollmentDate);
        }

        [Fact]
        public void Student_EnrollmentsCanBeSet()
        {
            var student = new Student { Enrollments = new List<Enrollment>() };
            Assert.Empty(student.Enrollments);
        }
    }

    public class InstructorTests
    {
        [Fact]
        public void Instructor_InheritsFromPerson()
        {
            var instructor = new Instructor();
            Assert.IsAssignableFrom<Person>(instructor);
        }

        [Fact]
        public void Instructor_HasHireDateProperty()
        {
            var date = DateTime.Parse("2020-01-15");
            var instructor = new Instructor { HireDate = date };
            Assert.Equal(date, instructor.HireDate);
        }

        [Fact]
        public void Instructor_CourseAssignmentsCanBeSet()
        {
            var instructor = new Instructor { CourseAssignments = new List<CourseAssignment>() };
            Assert.Empty(instructor.CourseAssignments);
        }

        [Fact]
        public void Instructor_OfficeAssignmentCanBeNull()
        {
            var instructor = new Instructor();
            Assert.Null(instructor.OfficeAssignment);
        }
    }

    public class CourseTests
    {
        [Fact]
        public void Course_PropertiesSetCorrectly()
        {
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1
            };

            Assert.Equal(1050, course.CourseID);
            Assert.Equal("Chemistry", course.Title);
            Assert.Equal(3, course.Credits);
            Assert.Equal(1, course.DepartmentID);
        }

        [Fact]
        public void Course_TeachingMaterialImagePathCanBeNull()
        {
            var course = new Course();
            Assert.Null(course.TeachingMaterialImagePath);
        }

        [Fact]
        public void Course_CollectionsCanBeSet()
        {
            var course = new Course
            {
                Enrollments = new List<Enrollment>(),
                CourseAssignments = new List<CourseAssignment>()
            };
            Assert.Empty(course.Enrollments);
            Assert.Empty(course.CourseAssignments);
        }
    }

    public class DepartmentTests
    {
        [Fact]
        public void Department_PropertiesSetCorrectly()
        {
            var dept = new Department
            {
                DepartmentID = 1,
                Name = "Engineering",
                Budget = 500000m,
                StartDate = DateTime.Parse("2020-01-01"),
                InstructorID = 5
            };

            Assert.Equal(1, dept.DepartmentID);
            Assert.Equal("Engineering", dept.Name);
            Assert.Equal(500000m, dept.Budget);
            Assert.Equal(5, dept.InstructorID);
        }

        [Fact]
        public void Department_InstructorIDCanBeNull()
        {
            var dept = new Department { InstructorID = null };
            Assert.Null(dept.InstructorID);
        }

        [Fact]
        public void Department_HasRowVersion()
        {
            var dept = new Department { RowVersion = new byte[] { 1, 2, 3 } };
            Assert.Equal(new byte[] { 1, 2, 3 }, dept.RowVersion);
        }
    }

    public class EnrollmentTests
    {
        [Fact]
        public void Enrollment_GradeCanBeNull()
        {
            var enrollment = new Enrollment { Grade = null };
            Assert.Null(enrollment.Grade);
        }

        [Theory]
        [InlineData(Grade.A)]
        [InlineData(Grade.B)]
        [InlineData(Grade.C)]
        [InlineData(Grade.D)]
        [InlineData(Grade.F)]
        public void Enrollment_AllGradesValid(Grade grade)
        {
            var enrollment = new Enrollment { Grade = grade };
            Assert.Equal(grade, enrollment.Grade);
        }

        [Fact]
        public void Enrollment_PropertiesSetCorrectly()
        {
            var enrollment = new Enrollment
            {
                EnrollmentID = 1,
                CourseID = 1050,
                StudentID = 1
            };
            Assert.Equal(1, enrollment.EnrollmentID);
            Assert.Equal(1050, enrollment.CourseID);
            Assert.Equal(1, enrollment.StudentID);
        }
    }

    public class NotificationModelTests
    {
        [Fact]
        public void Notification_PropertiesSetCorrectly()
        {
            var now = DateTime.Now;
            var notification = new Notification
            {
                Id = 1,
                EntityType = "Student",
                EntityId = "42",
                Operation = "CREATE",
                Message = "New student created",
                CreatedAt = now,
                CreatedBy = "Admin",
                IsRead = false,
                ReadAt = null
            };

            Assert.Equal(1, notification.Id);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("42", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Equal("New student created", notification.Message);
            Assert.Equal(now, notification.CreatedAt);
            Assert.Equal("Admin", notification.CreatedBy);
            Assert.False(notification.IsRead);
            Assert.Null(notification.ReadAt);
        }

        [Fact]
        public void Notification_ReadAtCanBeSet()
        {
            var readAt = DateTime.Now;
            var notification = new Notification { IsRead = true, ReadAt = readAt };
            Assert.True(notification.IsRead);
            Assert.Equal(readAt, notification.ReadAt);
        }
    }

    public class EntityOperationTests
    {
        [Fact]
        public void EntityOperation_HasAllExpectedValues()
        {
            Assert.Equal(0, (int)EntityOperation.CREATE);
            Assert.Equal(1, (int)EntityOperation.UPDATE);
            Assert.Equal(2, (int)EntityOperation.DELETE);
        }
    }

    public class ViewModelTests
    {
        [Fact]
        public void AssignedCourseData_PropertiesSetCorrectly()
        {
            var data = new AssignedCourseData
            {
                CourseID = 1050,
                Title = "Chemistry",
                Assigned = true
            };
            Assert.Equal(1050, data.CourseID);
            Assert.Equal("Chemistry", data.Title);
            Assert.True(data.Assigned);
        }

        [Fact]
        public void EnrollmentDateGroup_PropertiesSetCorrectly()
        {
            var date = DateTime.Parse("2023-09-01");
            var group = new EnrollmentDateGroup
            {
                EnrollmentDate = date,
                StudentCount = 5
            };
            Assert.Equal(date, group.EnrollmentDate);
            Assert.Equal(5, group.StudentCount);
        }

        [Fact]
        public void EnrollmentDateGroup_NullableDate()
        {
            var group = new EnrollmentDateGroup { EnrollmentDate = null };
            Assert.Null(group.EnrollmentDate);
        }

        [Fact]
        public void InstructorIndexData_PropertiesCanBeSet()
        {
            var data = new InstructorIndexData
            {
                Instructors = new List<Instructor>(),
                Courses = new List<Course>(),
                Enrollments = new List<Enrollment>()
            };
            Assert.Empty(data.Instructors);
            Assert.Empty(data.Courses);
            Assert.Empty(data.Enrollments);
        }
    }

    public class OfficeAssignmentTests
    {
        [Fact]
        public void OfficeAssignment_PropertiesSetCorrectly()
        {
            var office = new OfficeAssignment
            {
                InstructorID = 1,
                Location = "Smith 17"
            };
            Assert.Equal(1, office.InstructorID);
            Assert.Equal("Smith 17", office.Location);
        }
    }

    public class CourseAssignmentTests
    {
        [Fact]
        public void CourseAssignment_PropertiesSetCorrectly()
        {
            var assignment = new CourseAssignment
            {
                InstructorID = 1,
                CourseID = 1050
            };
            Assert.Equal(1, assignment.InstructorID);
            Assert.Equal(1050, assignment.CourseID);
        }
    }
}

